void Arrange(int A[],int n)
//n个整数存于数组 A中
int i=0,j=n-1,temp;//用类C语言编写,数组下标从 0开始。
while(i < j)
{while(i < j && A[i]%2==0) i++;
while(i < j && A[i]%2!=0) j--;
if(i < j)
{temp=A[i];A[i]=A[j];A[j]=temp;}}}//算法 Arrange结束。

